import React, { useEffect, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { io } from "socket.io-client";

const socket = io("http://localhost:3000");

export default function ChatRoom() {
  const [searchParams] = useSearchParams();
  const username = searchParams.get("username");
  const room = searchParams.get("room");

  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);

  useEffect(() => {
    if (username && room) {
      socket.emit("join-room", { username, room });

      socket.on("receive-message", (data) => {
        setChat((prev) => [...prev, data]);
      });
    }

    return () => socket.disconnect();
  }, []);

  const sendMessage = () => {
    if (message.trim()) {
      socket.emit("send-message", { text: message });
      setMessage("");
    }
  };

  return (
    <div className="h-screen p-4 bg-gray-100">
      <h1 className="text-xl font-bold mb-2">Room: {room}</h1>
      <div className="bg-white h-[80vh] overflow-y-auto p-4 rounded shadow mb-4">
        {chat.map((msg, i) => (
          <div key={i} className="mb-2">
            <strong>{msg.sender}</strong>: {msg.text}
            <span className="text-sm text-gray-500 ml-2">{msg.time}</span>
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input
          className="flex-1 p-2 border rounded"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Type a message..."
        />
        <button
          className="bg-blue-500 text-white px-4 py-2 rounded"
          onClick={sendMessage}
        >
          Send
        </button>
      </div>
    </div>
  );
}
